package com.google.gson.internal.reflect;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.lang.reflect.Field;
import java.lang.reflect.Method;

import org.junit.jupiter.api.BeforeAll;
import org.junit.jupiter.api.Test;
import org.mockito.MockedStatic;
import org.mockito.Mockito;

class ReflectionHelperTest {

  private static class DummyRecordHelper extends RecordHelper {
    Method accessor;

    DummyRecordHelper(Method accessor) {
      this.accessor = accessor;
    }

    @Override
    public Method getAccessor(Class<?> raw, Field field) {
      return accessor;
    }
  }

  private static Method dummyMethod;
  private static Field dummyField;

  @BeforeAll
  static void setup() throws NoSuchFieldException, NoSuchMethodException {
    dummyField = DummyClass.class.getDeclaredField("value");
    dummyMethod = DummyClass.class.getDeclaredMethod("getValue");
  }

  @Test
  void getAccessor_returnsMethodFromRecordHelper() throws Exception {
    // Use reflection to set private static final RECORD_HELPER field to a dummy instance
    Field recordHelperField = ReflectionHelper.class.getDeclaredField("RECORD_HELPER");
    recordHelperField.setAccessible(true);
    RecordHelper originalRecordHelper = (RecordHelper) recordHelperField.get(null);
    try {
      RecordHelper dummyRecordHelper = new DummyRecordHelper(dummyMethod);
      recordHelperField.set(null, dummyRecordHelper);

      Method result = ReflectionHelper.getAccessor(DummyClass.class, dummyField);
      assertNotNull(result);
      assertEquals(dummyMethod, result);
    } finally {
      recordHelperField.set(null, originalRecordHelper);
    }
  }

  // Dummy class to use for reflection
  private static class DummyClass {
    private int value;

    public int getValue() {
      return value;
    }
  }
}
